<?php
declare(strict_types=1);require __DIR__.'/bootstrap.php';$handle=strtolower(trim((string)($_GET['handle']??'')));$profile=null;$counts=['liked'=>0,'following'=>0];
if(vp3_db_available()&&preg_match('/^[a-z0-9_]{3,30}$/',$handle)){$stmt=vp3_db()->prepare("SELECT id,viewer_uuid,display_name,handle,avatar_url,bio,profile_visibility,created_at FROM viewer_accounts WHERE handle=? AND status='active' AND email_verified_at IS NOT NULL LIMIT 1");$stmt->execute([$handle]);$profile=$stmt->fetch()?:null;if($profile&&$profile['profile_visibility']==='public'){$s=vp3_db()->prepare("SELECT COUNT(*) FROM viewer_clip_actions WHERE viewer_id=? AND action_type='like'");$s->execute([(int)$profile['id']]);$counts['liked']=(int)$s->fetchColumn();$s=vp3_db()->prepare('SELECT (SELECT COUNT(*) FROM viewer_creator_follows WHERE viewer_id=?)+(SELECT COUNT(*) FROM viewer_show_follows WHERE viewer_id=?)');$s->execute([(int)$profile['id'],(int)$profile['id']]);$counts['following']=(int)$s->fetchColumn();}}
if(!$profile){http_response_code(404);$pageTitle='Viewer Not Found';require VP3_ROOT.'/includes/header.php';echo'<section class="network-subhero"><h1>Viewer not found.</h1></section>';require VP3_ROOT.'/includes/footer.php';exit;}
$pageTitle=$profile['display_name'];$pageDescription=$profile['profile_visibility']==='public'?(string)($profile['bio']?:'VP3 viewer profile'):'This viewer keeps their profile private.';$extraStyles=['assets/css/reels.css'];require VP3_ROOT.'/includes/header.php';?>
<section class="viewer-account-hero"><div><span class="eyebrow">VP3 Viewer</span><h1>@<?=vp3_e($profile['handle'])?></h1><p><?=vp3_e($profile['profile_visibility']==='public'?(string)($profile['bio']?:'Watching stories across VP3 Network.'):'This profile is private.')?></p></div><a class="button" href="clips.php">Open Reels</a></section>
<section class="viewer-profile-card"><div class="viewer-avatar"><?=vp3_e(strtoupper(substr((string)$profile['display_name'],0,1)))?></div><div><h2><?=vp3_e($profile['display_name'])?></h2><?php if($profile['profile_visibility']==='public'):?><p><?=$counts['liked']?> liked clips · <?=$counts['following']?> creators and shows followed</p><?php endif;?><span class="helper">Joined <?=vp3_e(date('F Y',strtotime((string)$profile['created_at'])))?></span></div></section>
<?php require VP3_ROOT.'/includes/footer.php';?>
